1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	  yearsWithMHPCO?: number;
11	  firstInsurance?: boolean;
12	  followUp?: boolean;
13	}
14	
15	export interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_BASE_PREMIUM = 100;
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	
32	function unmodifiedBasePremiumFor(item: Item): number {
33	  return BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
34	}
35	
36	function basePremiumFor(item: Item): number {
37	  const base = unmodifiedBasePremiumFor(item);
38	  const highEnchantmentSurcharge =
39	    item.enchantment === 5 ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
40	  const curseSurcharge = item.cursed ? CURSE_SURCHARGE_RATE : 0;
41	  return base * (1 + highEnchantmentSurcharge + curseSurcharge);
42	}
43	
44	const BLOCK_SIZE = 3;
45	const BLOCK_PREMIUM = 60;
46	
47	const LOYALTY_DISCOUNT_RATE = 0.2;
48	const LOYALTY_MIN_YEARS = 2;
49	
50	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
51	
52	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
53	
54	function applyLoyaltyDiscount(
55	  basePremium: number,
56	  yearsWithMHPCO: number | undefined,
57	): number {
58	  const qualifies =
59	    yearsWithMHPCO !== undefined && yearsWithMHPCO >= LOYALTY_MIN_YEARS;
60	  return qualifies ? basePremium * (1 - LOYALTY_DISCOUNT_RATE) : basePremium;
61	}
62	
63	function rateOfBaseWhen(
64	  condition: boolean | undefined,
65	  basePremium: number,
66	  rate: number,
67	): number {
68	  return condition ? basePremium * rate : 0;
69	}
70	
71	function groupByType(items: Item[]): Map<string, Item[]> {
72	  const groups = new Map<string, Item[]>();
73	  for (const item of items) {
74	    const group = groups.get(item.type) ?? [];
75	    group.push(item);
76	    groups.set(item.type, group);
77	  }
78	  return groups;
79	}
80	
81	function basePremiumForGroup(group: Item[]): number {
82	  if (group.length === BLOCK_SIZE) {
83	    return BLOCK_PREMIUM;
84	  }
85	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
86	}
87	
88	export function quote(input: QuoteInput): QuoteResult {
89	  const groups = [...groupByType(input.items).values()];
90	  const basePremium = groups.reduce(
91	    (sum, group) => sum + basePremiumForGroup(group),
92	    0,
93	  );
94	
95	  const unmodifiedBasePremium = input.items.reduce(
96	    (sum, item) => sum + unmodifiedBasePremiumFor(item),
97	    0,
98	  );
99	
100	  const firstInsuranceSurcharge = rateOfBaseWhen(
101	    input.firstInsurance,
102	    unmodifiedBasePremium,
103	    FIRST_INSURANCE_SURCHARGE_RATE,
104	  );
105	
106	  const followUpDiscount = rateOfBaseWhen(
107	    input.followUp,
108	    basePremium,
109	    FOLLOW_UP_DISCOUNT_RATE,
110	  );
111	
112	  const policyBase = applyLoyaltyDiscount(basePremium, input.yearsWithMHPCO);
113	
114	  return {
115	    premium:
116	      policyBase + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE,
117	  };
118	}
